import 'package:flutter/material.dart';
import 'package:flutter_localizations/flutter_localizations.dart';

// Generated by `flutter gen-l10n` into lib/l10n/generated/ (see l10n.yaml).
import 'generated/app_localizations.dart';

export 'generated/app_localizations.dart';

/// BirdCoder mobile i18n configuration helper.
///
/// AppLocalizations is generated from the ARB files under `lib/l10n/`.
/// Use [AppLocalizations.of] (or [tr]) to access translated strings.
class AppL10n {
  AppL10n._();

  /// Locales backed by an ARB file in `lib/l10n/`.
  static const List<Locale> supportedLocales = <Locale>[
    Locale('en'),
    Locale('zh'),
    Locale('zh', 'TW'),
  ];

  /// Localization delegates for [MaterialApp.localizationsDelegates].
  static const List<LocalizationsDelegate<dynamic>> localizationsDelegates =
      <LocalizationsDelegate<dynamic>>[
    AppLocalizations.delegate,
    GlobalMaterialLocalizations.delegate,
    GlobalWidgetsLocalizations.delegate,
    GlobalCupertinoLocalizations.delegate,
  ];

  /// Convenience accessor that returns a non-null [AppLocalizations].
  static AppLocalizations tr(BuildContext context) {
    final lookup = AppLocalizations.of(context);
    assert(
      lookup != null,
      'AppLocalizations not found. Ensure localizationsDelegates and '
      'supportedLocales are passed to the MaterialApp.',
    );
    return lookup!;
  }
}
